}

role_zh:
{
  "風格定義": {
    "藝術風格": "現代扁平化向量插畫 (Modern Flat Vector Illustration)",
    "媒介": "數位向量藝術 (Digital Vector Art)",
    "氛圍": "樂觀、愉快、旅遊海報風格",
    "渲染引擎模擬": "Adobe Illustrator / 向量化"
  },
  "視覺參數": {
    "線條與形狀": "線條簡潔鋒利，幾何形狀簡化，無複雜紋理，樹木與雲朵採用圓潤的有機形狀。",
    "色彩": "高飽和度，鮮豔配色。以青綠色 (Turquoise) 和青色 (Cyan) 代表水面/天空，溫暖的橙色和陶土色代表建築，蔥鬱的綠色代表植被，奶油色/黃色代表雲朵。",
    "光照": "柔和漸變的扁平光照，極少陰影，明亮的日光氛圍。"
  },
  "生成提示詞": "將輸入的照片轉換為高品質的現代扁平向量插畫，風格仿照專業旅遊海報。圖像應呈現簡化的形狀、潔淨的線條和光滑的啞光飾面。使用鮮豔的配色，包含明亮的青綠色水面、溫暖的橙色屋頂和茂盛的綠色葉子。天空應為亮藍色，配有風格化的蓬鬆雲朵。移除所有寫實紋理、噪點和顆粒。使其看起來像 Behance 或 Dribbble 上的專業數位藝術品。保持原始照片的構圖但將細節向量化。",
  "負面提示詞": "寫實, 逼真, 3d 渲染, 光澤, 閃亮, 顆粒感, 噪點, 模糊, 散景, 詳細紋理, 髒跡, 黑暗, 陰沉, 草圖, 粗糙線條, 低解析度, 攝影"
}

