{
  "title": "The Aether Workshop",
  "description": "A vibrant, nostalgic snapshot of two inventors collaborating on a clockwork masterpiece in a sun

role_zh:
{
  "標題": "以太工坊 (The Aether Workshop)",
  "描述": "一個充滿活力且懷舊的瞬間，捕捉了兩位發明家在陽光普照的蒸氣龐克工作室中，共同構思一件發條傑作的場景。",
  "提示詞": "使用所提供照片中的人物作為主要主體進行影像編輯。保留其核心神態。以獨特的復古 Kodachrome 膠片風格渲染場景，其特點是高對比度、豐富的飽和度和細膩的檔案底片顆粒。主體 1（男性）是一位專注的蒸氣龐克機械師，正在修補黃銅自動機的齒輪。主體 2（女性）是一位大膽的飛空艇飛行員，正趴在工作台上查看複雜的藍圖。他們周圍是一個陽光充足、充滿混亂感的車間，鋪滿了滴答作響的各種機械、蒸汽管道和零碎工具。",
  "細節": {
    "年份": "平行時空 1890s",
    "地點": "一個天花板很高、雜亂的閣樓工作室，帶有巨大的拱形窗戶，可以俯瞰霧霾籠罩的工業城市。",
    "燈光": ["透過除塵玻璃照射進來的強烈、溫暖陽光", "典型的幻燈片高對比陰影", "黃金時刻的輝光"],
    "構圖": "視平線中景鏡頭，營造親密、紀錄片的感覺。1:1 電影感構圖。",
    "情緒": ["專注", "協作", "具備創意"],
    "色調": ["拋光黃銅金", "深紅木棕", "經典的 Kodachrome 紅", "氧化銅青色"],
    "環境元素": "捕捉到光線的漂浮塵埃，銅管中散發出的柔和蒸汽，牆上的藍圖，成堆的齒輪和彈簧。",
    "主體 1 (機械師)": {
      "服飾": "沾有油漬的白色襯衫，袖子捲起，穿著沈重的皮革圍裙，黃銅焊接護目鏡掛在額頭上。",
      "行動": "手持精密的螺絲起子，微調機械臂內部的金色齒輪。"
    },
    "主體 2 (飛行員)": {
      "服飾": "帶有羊羔絨領子的棕色皮革飛行夾克，鮮豔的紅色絲巾和帆布長褲。",
      "表情": "好奇且具備分析性，正指著機器上的某個細節。",
      "行動": "一隻手扶著工作台，另一隻手拿著捲好的藍圖。"
    }
  }
}

