role_zh:
{
  "標題": "黑色電影的耳語 (Whispers of Noir)",
  "描述": "一張充滿磨砂質感的電影肖像，描繪了一位在煙霧繚繞、充滿迷離感的地下爵士酒廊中等待線索的硬漢偵探。",
  "提示詞": "使用所提供照片中的人物作為主要主體進行影像編輯。保留其核心神態。將主體 1（男性）轉變為一位疲憊的 1950 年代私家偵探，坐在一間煙霧滿溢的爵士俱樂部紅色天鵝絨卡座上。將影像渲染為超寫實的電影劇照，利用明暗對比燈光強調他的皮膚紋理與周圍繚繞的煙霧。影像必須細節豐富，使用 Arri Alexa 拍攝，具備淺景深以模糊背景中的樂隊，遵循 1:1 的幅面比例。",
  "細節": {
    "年份": "1954",
    "地點": "藍色天鵝絨酒廊 (Blue Velvet Lounge)，一間擁有紅木牆面與昏暗桌燈的地下俱樂部。",
    "燈光": ["明暗對照 (Chiaroscuro)", "暖色桌燈光輝", "來自舞台的冷藍色背光", "穿過煙霧的體積光束"],
    "構圖": "視平線中景特寫，強烈聚焦於主體的臉部。",
    "情緒": ["懷疑", "世故的疲憊", "專注"],
    "色調": ["威士計琥珀色", "天鵝絨紅", "深邃的影中黑", "煙草灰色"],
    "主體 1 (偵探)": {
      "服飾": "有質感的炭灰色風衣，內穿皺皺的西裝，打著鬆開的領帶，軟呢帽略微前傾。",
      "表情": "銳利且冷諷的目光，微瞇的雙眼配合緊繃的下頜。",
      "行動": "一隻手靠在半滿的威士忌酒杯旁，身體微傾向光影處。"
    }
  }
}

