role_zh:
{
  "版本": "2.1",
  "類型": "多幀冬日電影感 (Multi-frame Winter Cinematography)",
  "身份維護": {
    "參考人臉": "使用參考照片的人臉，實現 100% 身份準確度。",
    "一致性": "所有幀中為同一個人；面部結構、皮膚質感、髮型和年齡在可見處必須保持一致。"
  },
  "風格設定": {
    "電影感": "超寫實冬日電影美學，具備 85mm 鏡頭特性。",
    "色彩分級": "細微的藍色冬季調色，冷色調，柔和高光。",
    "氛圍": "柔和漫反射冬日光線，細碎的懸浮雪花，淡雅的冷霧。"
  },
  "幀列表": [
    {
      "幀 ID": "頂部幀 (Top Frame)",
      "描述": "一個雪地森林中的側面肖像。",
      "要求": {
        "表情": "從側面清晰可見的溫暖、自然的微笑。",
        "環境": {
          "地點": "積雪覆蓋的森林",
          "元素": ["緩緩飄落的雪", "清晰可見的呼氣煙霧", "輕微的冬日薄霧"]
        },
        "攝像機": "85mm, 淺景深, 超寫實電影質感"
      }
    },
    {
      "幀 ID": "中部幀 (Middle Frame)",
      "描述": "步行穿過狹窄雪林小徑時的背影特寫。",
      "要求": {
        "臉部可見性": "完全不可見臉部；嚴格的背影。",
        "身份暗示": "體型、姿勢和服裝必須清楚指示為同一個人。",
        "環境": {
          "禁止元素": ["禁止出現鳥居 (Torii gate)"],
          "樹木": "高大落葉樹略微彎曲，形成天然雪廊"
        },
        "服裝": "與首幀相同的深色冬裝外套和圍巾"
      }
    },
    {
      "幀 ID": "底部幀 (Bottom Frame)",
      "描述": "望向天空的極致特寫，周圍雪花飄落。",
      "要求": {
        "表情": "仰望天際時溫柔、溫暖的微笑。",
        "環境": {
          "元素": [
            "雪花環繞但不得觸碰面部",
            "僅在前景和背景中出現落雪",
            "不顯示呼氣水霧"
          ]
        },
        "攝像機": "85mm, 極淺景深, 銳利的皮膚質感, 選擇性對焦雪花"
      }
    }
  ],
  "全局約束": {
    "身份": "參考人臉必須在所有臉部可見幀中完美再現。",
    "連續性": "燈光、冬季色調、鏡頭特性和氛圍在所有幀中保持一致。",
    "寫實度": "超寫實，膠片級冬日準確性。"
  }
}

